"use client";

import "./globals.css";
import Sidebar from "@/components/Sidebar";
import { usePathname } from "next/navigation";
import { useEffect, useState } from "react";

export default function RootLayout({ children }) {
  const pathname = usePathname();
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Vérifier si le cookie de connexion existe
  useEffect(() => {
    const cookie = document.cookie
      .split("; ")
      .find((row) => row.startsWith("auth_token="));
    setIsAuthenticated(!!cookie);
  }, []);

  // Pages où le Sidebar NE DOIT PAS apparaître
  const hideSidebarOn = ["/login", "/signup", "/onboarding"];

  const shouldShowSidebar =
    isAuthenticated && !hideSidebarOn.includes(pathname);

  return (
    <html lang="fr">
      <body className="flex">
        {/* Sidebar uniquement si connecté */}
        {shouldShowSidebar && <Sidebar />}

        {/* Le contenu prend la largeur entière si pas de sidebar */}
        <main className={shouldShowSidebar ? "ml-64 w-full" : "w-full"}>
          {children}
        </main>
      </body>
    </html>
  );
}
